#!/bin/bash # Minimal health-check pattern set -euo pipefail
ERRORS=0 WARNINGS=0
ok() { echo "OK $1"; } warn() { echo "WARN $1"; WARNINGS=$((WARNINGS + 1)); } fail() { echo "FAIL $1"; ERRORS=$((ERRORS + 1)); }
check_service() { local name="$1" cmd="$2" if eval "$cmd" > /dev/null 2>&1; then ok "$name"; else fail "$name"; fi }
# Infrastructure check_service "Docker" "systemctl is-active docker" check_service "PostgreSQL" "docker exec nero-postgres pg_isready -U nero -q" check_service "Redis" "docker exec nero-redis redis-cli ping"
# Application check_service "nero-core" "systemctl --user is-active --quiet nero-core"
# Endpoints check_service "API /health" "curl -sf --max-time 5 http://127.0.0.1:8100/health"
# Resources DISK_PCT=$(df / --output=pcent | tail -1 | tr -d ' %') if [ "$DISK_PCT" -gt 90 ]; then fail "Disk: ${DISK_PCT}%" elif [ "$DISK_PCT" -gt 80 ]; then warn "Disk: ${DISK_PCT}%" else ok "Disk: ${DISK_PCT}%"; fi
# Exit code [ "$ERRORS" -gt 0 ] && exit 2 [ "$WARNINGS" -gt 0 ] && exit 1 exit 0
